
public class DecisionMaking {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
        int x = 1;
        while(x <= 4) {
        	System.out.println("While Loop " + x);
        	x++;
        }
	
	//do-while loop
	 int x1 = 20;
	do {
		System.out.println("do-while loop" + x1);
		x1++;
	}while(x1 < 25);
	
	//for loop
	for(int i = 2; i <= 4;i++)
		System.out.println("For Loop" +i);
	
	//for-each or enhanced for loop(to iterate)
	//ctrl and slash to comment
    //  /*.....mult-line comment....*/
	// /** Documentation purpose
  }
}
